///////////////////////////////////////////////////////////////////////////////
// IVP regression tests (cases 1-7)
//
// Compares current integrator output against golden data generated by
// generate_golden.cpp. Any deviation indicates a behavioral change that
// must be reviewed before proceeding with refactoring.
//
// Tolerances are 1e-12 absolute (matches expect_vector_match's EXPECT_NEAR
// semantics) — comfortably tight on unit-magnitude state vectors while
// accommodating ULP-level libm/Eigen 5 trig drift across CPUs (see
// commit babc607 for the original drift incident).
///////////////////////////////////////////////////////////////////////////////

#include "regression_utils.h"
#include <cmath>
#include <gtest/gtest.h>

using namespace tycho;
using namespace TychoTest;

class RegressionIVPTest : public VectorFunctionFixture {};

///////////////////////////////////////////////////////////////////////////////
// Helper: compare vector against golden with tolerance
///////////////////////////////////////////////////////////////////////////////
static void expect_vector_match(const Eigen::VectorXd &actual, const Eigen::VectorXd &golden,
                                double tol, const std::string &label) {
    ASSERT_EQ(actual.size(), golden.size()) << label << ": size mismatch";
    for (int i = 0; i < actual.size(); ++i) {
        EXPECT_NEAR(actual[i], golden[i], tol) << label << ": element " << i;
    }
}

///////////////////////////////////////////////////////////////////////////////
// Helper: compare against golden with combined relative + absolute bounds,
// i.e. |actual - golden| <= atol + rtol * |golden| (numpy allclose semantics).
// Use this when the state vector mixes magnitudes (e.g. km-scale positions
// alongside near-zero components), where a single absolute tolerance cannot be
// both tight on the small elements and loose enough for the large ones.
///////////////////////////////////////////////////////////////////////////////
static void expect_vector_close(const Eigen::VectorXd &actual, const Eigen::VectorXd &golden,
                                double rtol, double atol, const std::string &label) {
    ASSERT_EQ(actual.size(), golden.size()) << label << ": size mismatch";
    for (int i = 0; i < actual.size(); ++i) {
        const double bound = atol + rtol * std::abs(golden[i]);
        EXPECT_LE(std::abs(actual[i] - golden[i]), bound)
            << label << ": element " << i << " (actual=" << actual[i]
            << ", golden=" << golden[i] << ", bound=" << bound << ")";
    }
}

///////////////////////////////////////////////////////////////////////////////
// Case 1: Two-body DOPRI54 — LEO circular orbit, quarter period
///////////////////////////////////////////////////////////////////////////////
TEST_F(RegressionIVPTest, Case01_TwoBody_DOPRI54) {
    Kepler kep(MU_EARTH);
    Integrator<Kepler> integ(kep, IVPAlg::DOPRI54, 10.0);
    integ.set_abs_tol(1e-12);
    integ.set_rel_tol(1e-13);

    auto x0 = leo_circular_x0();
    double tf = leo_period() / 4.0;
    auto xf = integ.integrate(x0, tf);

    std::ifstream f(golden_path("ivp_01_twobody_dopri54.bin"), std::ios::binary);
    ASSERT_TRUE(f.good()) << "Golden file not found: ivp_01_twobody_dopri54.bin";
    auto golden_xf = read_vector(f);

    expect_vector_match(xf, golden_xf, 1e-12, "Case01_xf");
}

